class Solution:
    def minimumSeconds(self, nums):
        n = len(nums)
        pos = {}
        for i, v in enumerate(nums):
            pos.setdefault(v, []).append(i)
        best = n
        for idxs in pos.values():
            worst = 0
            for i in range(n):
                d = min(min(abs(i - p), n - abs(i - p)) for p in idxs)
                if d > worst:
                    worst = d
            if worst < best:
                best = worst
        return best

