class Solution:
    def minimumSeconds(self, nums):
        n = len(nums)
        pos = {}
        for i, v in enumerate(nums):
            pos.setdefault(v, []).append(i)
        ans = n
        for idxs in pos.values():
            maxgap = 0
            m = len(idxs)
            for i in range(m):
                nxt = idxs[(i + 1) % m]
                gap = nxt - idxs[i]
                if gap <= 0:
                    gap += n
                if gap > maxgap:
                    maxgap = gap
            cost = maxgap // 2
            if cost < ans:
                ans = cost
        return ans

