var minimumSeconds = function(nums) {
    const n = nums.length;
    const pos = new Map();
    for (let i = 0; i < n; i++) {
        if (!pos.has(nums[i])) pos.set(nums[i], []);
        pos.get(nums[i]).push(i);
    }
    let ans = n;
    for (const idxs of pos.values()) {
        let maxgap = 0;
        const m = idxs.length;
        for (let i = 0; i < m; i++) {
            let gap = idxs[(i + 1) % m] - idxs[i];
            if (gap <= 0) gap += n;
            if (gap > maxgap) maxgap = gap;
        }
        const cost = Math.floor(maxgap / 2);
        if (cost < ans) ans = cost;
    }
    return ans;
};
